import React, { useMemo } from 'react';
import { LayoutDashboard } from 'lucide-react';
import { ResponsiveContainer, AreaChart, CartesianGrid, XAxis, YAxis, Tooltip, Area } from 'recharts';

const DashboardView = ({ historico, setCurrentView }) => {
  const chartData = useMemo(() => {
    return [...historico].reverse().map(item => ({
      data: item.data.split(' ')[0],
      sentimento: item.sentimento,
      valor: item.sentimento === 'Feliz' ? 3 : item.sentimento === 'Neutro' ? 2 : 1
    }));
  }, [historico]);

  const stats = useMemo(() => {
    return {
      total: historico.length,
      hoje: historico.filter(i => i.data.startsWith(new Date().toLocaleDateString('pt-BR'))).length,
      dominante: historico.length > 0 ? Object.entries(historico.reduce((acc, curr) => {
        acc[curr.sentimento] = (acc[curr.sentimento] || 0) + 1;
        return acc;
      }, {})).sort((a, b) => b[1] - a[1])[0][0] : 'Nenhum'
    };
  }, [historico]);

  return (
    <div className="dashboard-view">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <h2><LayoutDashboard style={{ marginRight: 12, verticalAlign: 'middle' }} /> Painel de Evolução</h2>
        <button className="reset-btn" onClick={() => setCurrentView('app')}>Voltar ao Chat</button>
      </div>
      <div className="stats-grid">
        <div className="stat-card">
          <span className="stat-value">{stats.total}</span>
          <span className="stat-label">Registros</span>
        </div>
        <div className="stat-card">
          <span className="stat-value">{stats.hoje}</span>
          <span className="stat-label">Hoje</span>
        </div>
        <div className="stat-card">
          <span className="stat-value" style={{ fontSize: '1.1rem' }}>{stats.dominante}</span>
          <span className="stat-label">Humor Dominante</span>
        </div>
      </div>
      <div className="chart-container">
        <ResponsiveContainer width="100%" height="100%">
          <AreaChart data={chartData}>
            <defs>
              <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="#8b5cf6" stopOpacity={0.3} />
                <stop offset="95%" stopColor="#8b5cf6" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" strokeOpacity={0.05} vertical={false} />
            <XAxis dataKey="data" stroke="#64748b" fontSize={10} tickLine={false} />
            <YAxis hide />
            <Tooltip contentStyle={{ background: '#1e293b', border: 'none', borderRadius: '8px', fontSize: '12px' }} />
            <Area type="monotone" dataKey="valor" stroke="#8b5cf6" fillOpacity={1} fill="url(#colorVal)" strokeWidth={2} />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default DashboardView;
